import React, { useState, useRef, useEffect, useCallback } from 'react';

// ==================== TOOLBOX COMPONENT ====================
const Toolbox = ({ tools, selectedTool, onSelectTool }) => {
    return (
        <div className="toolbox">
            {tools.map(tool => (
                <button
                    key={tool.id}
                    className={`tool-btn ${selectedTool === tool.id ? 'active' : ''}`}
                    onClick={() => onSelectTool(tool.id)}
                    title={tool.name}
                >
                    {tool.icon}
                </button>
            ))}
        </div>
    );
};

// ==================== DIKTIS GAUGE COMPONENT ====================
const DiktisGauge = ({ props: p, isSelected, onSelect, onDragEnd, position }) => {
    const canvasRef = useRef(null);
    const [loadedImage, setLoadedImage] = useState(null);
    const [isDragging, setIsDragging] = useState(false);
    const dragStartPos = useRef({ x: 0, y: 0 });
    const dragStartElementPos = useRef({ x: 0, y: 0 });

    // Load background image
    useEffect(() => {
        if (p.backgroundImage && p.backgroundImage !== '') {
            const img = new Image();
            img.crossOrigin = "Anonymous";
            img.src = p.backgroundImage;
            img.onload = () => setLoadedImage(img);
            img.onerror = () => setLoadedImage(null);
        } else {
            setLoadedImage(null);
        }
    }, [p.backgroundImage]);

    // Draw gauge
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        const size = 250;
        canvas.width = size;
        canvas.height = size;

        const centerX = size / 2;
        const centerY = size / 2;

        ctx.clearRect(0, 0, size, size);

        // Background color
        if (p.backgroundColor && p.backgroundColor !== 'transparent') {
            ctx.fillStyle = p.backgroundColor;
            ctx.fillRect(0, 0, size, size);
        }

        // Background image
        if (loadedImage) {
            const imgSize = size * (p.backgroundImageSize / 100);
            const imgX = (size - imgSize) / 2;
            const imgY = (size - imgSize) / 2;
            ctx.save();
            ctx.globalAlpha = p.backgroundImageOpacity / 100;
            ctx.drawImage(loadedImage, imgX, imgY, imgSize, imgSize);
            ctx.restore();
        }

        const radius = size * 0.7;
        const startAngleRad = (p.startAngle * Math.PI) / 180;
        const endAngleRad = (p.endAngle * Math.PI) / 180;

        // Arc
        ctx.beginPath();
        ctx.arc(centerX, centerY, radius, startAngleRad, endAngleRad);
        ctx.strokeStyle = "#666";
        ctx.lineWidth = 2;
        ctx.stroke();

        // Tick marks
        for (let i = 0; i <= 10; i++) {
            const t = i / 10;
            const angle = p.startAngle + (t * (p.endAngle - p.startAngle));
            const rad = (angle * Math.PI) / 180;
            const x1 = centerX + (radius - 8) * Math.cos(rad);
            const y1 = centerY + (radius - 8) * Math.sin(rad);
            const x2 = centerX + (radius + 2) * Math.cos(rad);
            const y2 = centerY + (radius + 2) * Math.sin(rad);

            ctx.beginPath();
            ctx.moveTo(x1, y1);
            ctx.lineTo(x2, y2);
            ctx.strokeStyle = "#888";
            ctx.lineWidth = i % 2 === 0 ? 2 : 1;
            ctx.stroke();
        }

        // Needle
        const normalized = Math.min(1, Math.max(0, (p.value - p.min) / (p.max - p.min)));
        const angleRange = p.endAngle - p.startAngle;
        const needleAngle = p.startAngle + (normalized * angleRange);
        const needleRad = (needleAngle * Math.PI) / 180;
        const needleLength = radius - 10;
        const needleX = centerX + needleLength * Math.cos(needleRad);
        const needleY = centerY + needleLength * Math.sin(needleRad);

        ctx.shadowBlur = 4;
        ctx.shadowColor = "rgba(0,0,0,0.3)";
        ctx.beginPath();
        ctx.moveTo(centerX, centerY);
        ctx.lineTo(needleX, needleY);
        ctx.strokeStyle = p.pointerColor;
        ctx.lineWidth = p.pointerWidth;
        ctx.stroke();

        // Center circle
        ctx.beginPath();
        ctx.arc(centerX, centerY, 8, 0, 2 * Math.PI);
        ctx.fillStyle = p.pointerColor;
        ctx.fill();
        ctx.beginPath();
        ctx.arc(centerX, centerY, 4, 0, 2 * Math.PI);
        ctx.fillStyle = "#fff";
        ctx.fill();
        ctx.shadowBlur = 0;

        // Value text
        if (p.showValue !== false) {
            ctx.font = "bold 18px 'Verdana'";
            ctx.fillStyle = p.pointerColor;
            ctx.textAlign = "center";
            ctx.fillText(`${Math.round(p.value)}${p.unit}`, centerX, centerY - radius - 10);
        }

        // Title
        if (p.title) {
            ctx.font = "12px 'Verdana'";
            ctx.fillStyle = "#aaa";
            ctx.textAlign = "center";
            ctx.fillText(p.title, centerX, centerY + radius + 20);
        }
    }, [p, loadedImage]);

    const handleMouseDown = (e) => {
        if (!isSelected) return;
        e.stopPropagation();
        setIsDragging(true);
        dragStartPos.current = { x: e.clientX, y: e.clientY };
        dragStartElementPos.current = { x: position.x, y: position.y };
    };

    const handleMouseMove = useCallback((e) => {
        if (!isDragging) return;
        e.stopPropagation();
        const dx = e.clientX - dragStartPos.current.x;
        const dy = e.clientY - dragStartPos.current.y;
        onDragEnd({
            x: dragStartElementPos.current.x + dx,
            y: dragStartElementPos.current.y + dy
        });
    }, [isDragging, onDragEnd]);

    const handleMouseUp = useCallback(() => {
        setIsDragging(false);
    }, []);

    useEffect(() => {
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging, handleMouseMove, handleMouseUp]);

    return (
        <div
            className={`gauge-container ${isSelected ? 'selected' : ''}`}
            style={{
                position: 'absolute',
                left: position.x,
                top: position.y,
                cursor: isSelected ? 'move' : 'pointer',
            }}
            onClick={(e) => { e.stopPropagation(); onSelect(); }}
            onMouseDown={handleMouseDown}
        >
            <canvas ref={canvasRef} className="gauge-canvas" />
        </div>
    );
};

// ==================== PROPERTIES PANEL ====================
const PropertiesPanel = ({ selectedGauge, onUpdate }) => {
    if (!selectedGauge) {
        return (
            <div className="properties-panel">
                <h3>Properties</h3>
                <p style={{ color: '#888', marginTop: 20 }}>Select a gauge to edit</p>
            </div>
        );
    }

    const p = selectedGauge.props;

    const handleChange = (key, value) => {
        onUpdate({ ...p, [key]: value });
    };

    return (
        <div className="properties-panel">
            <h3>Diktis Properties</h3>

            <div className="prop-group">
                <label>Title</label>
                <input
                    type="text"
                    value={p.title || ''}
                    onChange={e => handleChange('title', e.target.value)}
                    placeholder="Gauge Title"
                />
            </div>

            <div className="prop-row">
                <div className="prop-group">
                    <label>Min</label>
                    <input
                        type="number"
                        value={p.min}
                        onChange={e => handleChange('min', parseFloat(e.target.value))}
                    />
                </div>
                <div className="prop-group">
                    <label>Max</label>
                    <input
                        type="number"
                        value={p.max}
                        onChange={e => handleChange('max', parseFloat(e.target.value))}
                    />
                </div>
            </div>

            <div className="prop-group">
                <label>Value: {p.value}</label>
                <input
                    type="range"
                    min={p.min}
                    max={p.max}
                    step="1"
                    value={p.value}
                    onChange={e => handleChange('value', parseFloat(e.target.value))}
                />
            </div>

            <div className="prop-group">
                <label>Unit</label>
                <input
                    type="text"
                    value={p.unit || ''}
                    onChange={e => handleChange('unit', e.target.value)}
                    placeholder="RPM, °C, %"
                />
            </div>

            <div className="prop-group">
                <label>Pointer Color</label>
                <input
                    type="color"
                    value={p.pointerColor}
                    onChange={e => handleChange('pointerColor', e.target.value)}
                />
            </div>

            <div className="prop-group">
                <label>Pointer Width: {p.pointerWidth}px</label>
                <input
                    type="range"
                    min="1"
                    max="20"
                    step="1"
                    value={p.pointerWidth}
                    onChange={e => handleChange('pointerWidth', parseInt(e.target.value))}
                />
            </div>

            <div className="prop-group">
                <label>Start Angle: {p.startAngle}°</label>
                <input
                    type="range"
                    min="-180"
                    max="180"
                    step="5"
                    value={p.startAngle}
                    onChange={e => handleChange('startAngle', parseFloat(e.target.value))}
                />
            </div>

            <div className="prop-group">
                <label>End Angle: {p.endAngle}°</label>
                <input
                    type="range"
                    min="-180"
                    max="180"
                    step="5"
                    value={p.endAngle}
                    onChange={e => handleChange('endAngle', parseFloat(e.target.value))}
                />
            </div>

            <div className="prop-group">
                <label>Background Color</label>
                <input
                    type="color"
                    value={p.backgroundColor || '#1a1a2e'}
                    onChange={e => handleChange('backgroundColor', e.target.value)}
                />
            </div>

            <div className="prop-group">
                <label>Background Image URL</label>
                <input
                    type="text"
                    value={p.backgroundImage || ''}
                    onChange={e => handleChange('backgroundImage', e.target.value)}
                    placeholder="https://example.com/image.png"
                />
                <small style={{ color: '#666', fontSize: 10 }}>Supports PNG, JPG, SVG</small>
            </div>

            <div className="prop-group">
                <label>Image Size: {p.backgroundImageSize}%</label>
                <input
                    type="range"
                    min="20"
                    max="150"
                    step="5"
                    value={p.backgroundImageSize}
                    onChange={e => handleChange('backgroundImageSize', parseInt(e.target.value))}
                />
            </div>

            <div className="prop-group">
                <label>Image Opacity: {p.backgroundImageOpacity}%</label>
                <input
                    type="range"
                    min="0"
                    max="100"
                    step="5"
                    value={p.backgroundImageOpacity}
                    onChange={e => handleChange('backgroundImageOpacity', parseInt(e.target.value))}
                />
            </div>

            <div className="prop-group">
                <label style={{ display: 'flex', alignItems: 'center', cursor: 'pointer' }}>
                    <input
                        type="checkbox"
                        checked={p.showValue !== false}
                        onChange={e => handleChange('showValue', e.target.checked)}
                        style={{ width: 'auto', marginRight: 8 }}
                    />
                    Show Value
                </label>
            </div>
        </div>
    );
};

// ==================== MAIN EDITOR ====================
const DiktisEditor = () => {
    const [tools] = useState([
        { id: 'select', name: 'Select', icon: '🖱️' },
        { id: 'diktis', name: 'Diktis', icon: '📊' },
    ]);
    const [selectedTool, setSelectedTool] = useState('diktis');
    const [gauges, setGauges] = useState([]);
    const [selectedId, setSelectedId] = useState(null);
    const canvasRef = useRef(null);
    const nextId = useRef(1);

    const selectedGauge = gauges.find(g => g.id === selectedId);

    const addGauge = (x, y) => {
        const newId = nextId.current++;
        setGauges(prev => [...prev, {
            id: newId,
            position: { x: x - 125, y: y - 125 },
            props: {
                min: 0,
                max: 100,
                value: 50,
                title: `Diktis ${newId}`,
                unit: "",
                pointerColor: "#ff3333",
                pointerWidth: 4,
                startAngle: -135,
                endAngle: 135,
                showValue: true,
                backgroundColor: "#1a1a2e",
                backgroundImage: "",
                backgroundImageSize: 100,
                backgroundImageOpacity: 100,
            }
        }]);
        setSelectedId(newId);
    };

    const updateGauge = (id, newProps) => {
        setGauges(prev => prev.map(g => g.id === id ? { ...g, props: newProps } : g));
    };

    const updatePosition = (id, newPosition) => {
        setGauges(prev => prev.map(g => g.id === id ? { ...g, position: newPosition } : g));
    };

    const handleCanvasClick = (e) => {
        if (selectedTool !== 'diktis') return;
        // Don't add if clicking on a gauge
        if (e.target.closest('.gauge-container')) return;
        const rect = canvasRef.current.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const y = e.clientY - rect.top;
        addGauge(x, y);
    };

    const handleSelect = (id) => {
        setSelectedId(id);
        setSelectedTool('select');
    };

    // Deselect when clicking on empty canvas
    const handleCanvasClickDeselect = (e) => {
        if (e.target === canvasRef.current || e.target.classList?.contains('canvas-container')) {
            setSelectedId(null);
        }
    };

    return (
        <div className="editor-container">
            {/* LEFT PANEL - TOOLBOX */}
            <Toolbox tools={tools} selectedTool={selectedTool} onSelectTool={setSelectedTool} />

            {/* CENTER CANVAS */}
            <div
                className="canvas-container"
                ref={canvasRef}
                onClick={(e) => {
                    handleCanvasClick(e);
                    handleCanvasClickDeselect(e);
                }}
            >
                {gauges.map(gauge => (
                    <DiktisGauge
                        key={gauge.id}
                        props={gauge.props}
                        position={gauge.position}
                        isSelected={selectedId === gauge.id}
                        onSelect={() => handleSelect(gauge.id)}
                        onDragEnd={(newPos) => updatePosition(gauge.id, newPos)}
                    />
                ))}
                {gauges.length === 0 && selectedTool === 'diktis' && (
                    <div className="canvas-placeholder">
                        Click anywhere to add a Diktis gauge
                    </div>
                )}
            </div>

            {/* RIGHT PANEL - PROPERTIES */}
            <PropertiesPanel
                selectedGauge={selectedGauge}
                onUpdate={(props) => updateGauge(selectedId, props)}
            />
        </div>
    );
};

export default DiktisEditor;
